  sum += sampleChromatic(tex, uv + vec2(0.0, 0.0), refractionOffset, dispersion) * 0.16;
  sum += sampleChromatic(tex, uv + vec2(step, 0.0), refractionOffset, dispersion) * 0.12;
  
